// Define the function to calculate column widths
function calculateColumnWidths(config) {
  const gridTemplateColumns = config.gridTemplateColumns.split(' ');
  const gridGap = parseInt(config.gridGap);
  const items = config.items;

  // Calculate the total width of the grid
  let totalWidth = 0;
  for (let i = 0; i < gridTemplateColumns.length; i++) {
    totalWidth += gridTemplateColumns[i].replace('fr', '');
  }

  // Iterate over the grid items and adjust the column widths
  for (let i = 0; i < items.length; i++) {
    totalWidth -= parseInt(items[i].width);
  }

  // Calculate the column widths
  const columnWidths = [];
  for (let i = 0; i < gridTemplateColumns.length; i++) {
    columnWidths.push(gridTemplateColumns[i] + 'px');
  }

  return { columnWidths };
}

