class Solution:
    def calculate_column_widths(self, config):
        grid_template_columns = config['grid_template_columns'].split(' ')
        grid_gap = int(config['grid_gap'])
        items = config['items']

        # Calculate the total width of the grid
        total_width = 0
        for column in grid_template_columns:
            total_width += int(column.replace('fr', ''))

        # Iterate over the grid items and adjust the column widths
        for item in items:
            total_width -= int(item['width'])

        # Calculate the column widths
        column_widths = []
        for i in range(len(grid_template_columns)):
            column_widths.append(grid_template_columns[i] + 'px')

        return { 'columnWidths': column_widths }

